import React, { useMemo, useState } from 'react';
import { Transaction } from '../../types';
import { TrendingDown, BarChart3, Target, Plus, Pencil, Wallet, ArrowUp, ChevronDown } from 'lucide-react';
import Tooltip from '../Tooltip';

interface FinanceAnalyticsProps {
    transactions: Transaction[];
    period: 'this-month' | 'last-month' | 'all';
}

const FinanceAnalytics: React.FC<FinanceAnalyticsProps> = ({ transactions, period }) => {
    // Budget State (Persisted in localStorage for simplicity in this demo)
    const [budget, setBudget] = useState<number>(() => {
        const saved = localStorage.getItem('kalina_monthly_budget');
        return saved ? Number(saved) : 0;
    });
    const [isEditingBudget, setIsEditingBudget] = useState(false);
    const [tempBudget, setTempBudget] = useState('');
    const [hoveredDay, setHoveredDay] = useState<number | null>(null);

    // New state for accordion
    const [isBreakdownExpanded, setIsBreakdownExpanded] = useState(false);

    const saveBudget = () => {
        const val = Number(tempBudget);
        if (!isNaN(val)) {
            setBudget(val);
            localStorage.setItem('kalina_monthly_budget', val.toString());
        }
        setIsEditingBudget(false);
    };

    const analytics = useMemo(() => {
        const expenseTransactions = transactions.filter(t => t.type === 'expense');
        const totalExpense = expenseTransactions.reduce((sum, t) => sum + Number(t.amount), 0);

        // 1. Category Breakdown
        const categoryMap: Record<string, number> = {};
        expenseTransactions.forEach(t => {
            categoryMap[t.category] = (categoryMap[t.category] || 0) + Number(t.amount);
        });

        const categories = Object.entries(categoryMap)
            .map(([name, value]) => ({ name, value, percentage: totalExpense > 0 ? (value / totalExpense) * 100 : 0 }))
            .sort((a, b) => b.value - a.value);

        // 2. Daily Data
        const dailyMap: Record<number, number> = {};
        expenseTransactions.forEach(t => {
            const date = new Date(t.transaction_date).getDate();
            dailyMap[date] = (dailyMap[date] || 0) + Number(t.amount);
        });

        let daysInMonth = 30; 
        const now = new Date();
        if (period === 'this-month') {
            daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
        } else if (period === 'last-month') {
            daysInMonth = new Date(now.getFullYear(), now.getMonth(), 0).getDate();
        }

        const trendData = Array.from({ length: daysInMonth }, (_, i) => {
            const day = i + 1;
            return { day, amount: dailyMap[day] || 0 };
        });

        const maxDailySpend = Math.max(...trendData.map(d => d.amount), 1); 
        const zeroSpendDays = trendData.filter(d => d.amount === 0).length;

        // 3. Smart Stats
        const daysCount = new Set(expenseTransactions.map(t => new Date(t.transaction_date).toDateString())).size || 1;
        const dailyAverage = totalExpense / Math.max(daysCount, 1);
        const highestSpendCategory = categories[0] || { name: 'None', value: 0 };

        // 4. Budget Stats
        const budgetUsed = budget > 0 ? (totalExpense / budget) * 100 : 0;
        const remaining = Math.max(budget - totalExpense, 0);

        return { totalExpense, categories, trendData, maxDailySpend, dailyAverage, highestSpendCategory, budgetUsed, remaining, zeroSpendDays };
    }, [transactions, period, budget]);

    const colors = ['bg-rose-500', 'bg-orange-500', 'bg-amber-500', 'bg-emerald-500', 'bg-blue-500', 'bg-indigo-500', 'bg-purple-500'];

    return (
        <div className="space-y-6 animate-fade-in-up">

            {/* Budget Card */}
            <div className="bg-white dark:bg-[#1e1f22] p-5 rounded-3xl border border-gray-100 dark:border-gray-800 shadow-sm relative overflow-hidden">
                <div className="flex justify-between items-start mb-4 relative z-10">
                    <div>
                        <h3 className="font-bold text-gray-900 dark:text-white flex items-center gap-2">
                            <Target className="w-4 h-4 text-emerald-500" />
                            Monthly Budget
                        </h3>
                        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                            {budget > 0 ? `₹${analytics.remaining.toLocaleString()} remaining` : 'Set a limit to track savings'}
                        </p>
                    </div>
                    <button 
                        onClick={() => { setTempBudget(budget.toString()); setIsEditingBudget(true); }}
                        className="p-2 bg-gray-100 dark:bg-gray-800 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
                    >
                        {budget > 0 ? <Pencil className="w-4 h-4 text-gray-600 dark:text-gray-300" /> : <Plus className="w-4 h-4 text-emerald-600" />}
                    </button>
                </div>

                {isEditingBudget ? (
                    <div className="flex gap-2 relative z-10">
                        <input 
                            type="number" 
                            value={tempBudget}
                            onChange={(e) => setTempBudget(e.target.value)}
                            placeholder="Enter Amount"
                            className="flex-1 bg-gray-50 dark:bg-black/20 border border-gray-200 dark:border-gray-700 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                            autoFocus
                        />
                        <button onClick={saveBudget} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-sm font-bold">Save</button>
                    </div>
                ) : (
                    budget > 0 && (
                        <div className="relative z-10">
                            <div className="flex justify-between text-xs font-bold mb-1.5">
                                <span className="text-gray-500 dark:text-gray-400">{analytics.budgetUsed.toFixed(0)}% Used</span>
                                <span className="text-gray-900 dark:text-white">₹{analytics.totalExpense.toLocaleString()} / ₹{budget.toLocaleString()}</span>
                            </div>
                            <div className="h-3 w-full bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
                                <div 
                                    className={`h-full rounded-full transition-all duration-1000 ease-out ${analytics.budgetUsed > 100 ? 'bg-red-500' : analytics.budgetUsed > 80 ? 'bg-orange-500' : 'bg-emerald-500'}`}
                                    style={{ width: `${Math.min(analytics.budgetUsed, 100)}%` }}
                                ></div>
                            </div>
                        </div>
                    )
                )}
            </div>

            {/* Smart Stats Grid */}
            <div className="grid grid-cols-2 gap-3">
                <div className="bg-white dark:bg-[#1e1f22] p-4 rounded-2xl border border-gray-100 dark:border-gray-800 shadow-sm">
                    <div className="flex items-center gap-2 mb-2 text-rose-500">
                        <TrendingDown className="w-4 h-4" />
                        <span className="text-[10px] font-bold uppercase tracking-wider">Daily Avg</span>
                    </div>
                    <p className="text-2xl font-bold text-gray-900 dark:text-white">₹{Math.round(analytics.dailyAverage).toLocaleString()}</p>
                </div>
                <div className="bg-white dark:bg-[#1e1f22] p-4 rounded-2xl border border-gray-100 dark:border-gray-800 shadow-sm">
                    <div className="flex items-center gap-2 mb-2 text-emerald-500">
                        <Wallet className="w-4 h-4" />
                        <span className="text-[10px] font-bold uppercase tracking-wider">Zero Spend</span>
                    </div>
                    <p className="text-2xl font-bold text-gray-900 dark:text-white">{analytics.zeroSpendDays} <span className="text-sm font-medium text-gray-400">days</span></p>
                </div>
            </div>

            {/* Spending Trend Graph (Bar Chart) */}
            <div className="bg-white dark:bg-[#1e1f22] p-6 rounded-3xl border border-gray-100 dark:border-gray-800 shadow-sm">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-bold text-gray-900 dark:text-white flex items-center gap-2">
                        <BarChart3 className="w-4 h-4 text-indigo-500" />
                        Spending Trend
                    </h3>
                    <div className="text-[10px] font-bold uppercase text-gray-400 dark:text-gray-500 bg-gray-100 dark:bg-gray-800 px-2 py-1 rounded-md">
                        {period.replace('-', ' ')}
                    </div>
                </div>

                <div className="relative h-64 w-full flex items-end gap-1 sm:gap-2">
                    {/* Average Line */}
                    {analytics.dailyAverage > 0 && (
                        <div 
                            className="absolute left-0 right-0 border-t border-dashed border-rose-400/50 z-0 flex items-center"
                            style={{ bottom: `${(analytics.dailyAverage / analytics.maxDailySpend) * 100}%` }}
                        >
                            <span className="text-[9px] text-rose-500 font-bold bg-white dark:bg-[#1e1f22] px-1 ml-auto -mt-2.5">Avg</span>
                        </div>
                    )}

                    {analytics.trendData.map((data) => {
                        const heightPct = (data.amount / analytics.maxDailySpend) * 100;
                        const isZero = data.amount === 0;
                        const isHovered = hoveredDay === data.day;

                        // Min height for visibility
                        const visualHeight = isZero ? '4%' : `${Math.max(heightPct, 4)}%`; 

                        let barColor = isZero 
                            ? 'bg-gray-100 dark:bg-gray-800' 
                            : 'bg-indigo-500 dark:bg-indigo-600';

                        if (isHovered && !isZero) barColor = 'bg-rose-500 dark:bg-rose-600 scale-105';

                        return (
                            <div 
                                key={data.day}
                                className="flex-1 flex flex-col items-center justify-end h-full group relative"
                                onMouseEnter={() => setHoveredDay(data.day)}
                                onMouseLeave={() => setHoveredDay(null)}
                            >
                                {/* Tooltip Container wrapping the bar itself so it's relative to bar height */}
                                <div 
                                    className={`w-full relative transition-all duration-300 ease-out ${barColor} rounded-t-lg`}
                                    style={{ height: visualHeight }}
                                >
                                    {isHovered && (
                                        <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 flex flex-col items-center bg-gray-900 text-white text-[10px] font-bold px-2 py-1.5 rounded-lg shadow-xl z-20 pointer-events-none whitespace-nowrap">
                                            <span>Day {data.day}</span>
                                            <span className="text-emerald-400 text-xs">₹{data.amount.toLocaleString()}</span>
                                            <div className="absolute -bottom-1 w-2 h-2 bg-gray-900 rotate-45"></div>
                                        </div>
                                    )}

                                    {/* Top glow for high spenders */}
                                    {!isZero && heightPct > 80 && (
                                        <div className="absolute top-0 left-0 right-0 h-1 bg-white/30 rounded-t-lg"></div>
                                    )}
                                </div>

                                {/* Label (Show specific days to avoid clutter) */}
                                <span className={`text-[9px] mt-2 font-medium ${isHovered ? 'text-gray-900 dark:text-white' : 'text-gray-400 dark:text-gray-600'}`}>
                                    {data.day % 5 === 0 || data.day === 1 ? data.day : ''}
                                </span>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Category Breakdown - ACCORDION */}
            <div className="bg-white dark:bg-[#1e1f22] p-5 rounded-3xl border border-gray-100 dark:border-gray-800 shadow-sm transition-all duration-300">
                <div 
                    className="flex justify-between items-center mb-4 cursor-pointer select-none"
                    onClick={() => setIsBreakdownExpanded(!isBreakdownExpanded)}
                >
                    <h3 className="font-bold text-gray-900 dark:text-white flex items-center gap-2">
                        <ArrowUp className="w-4 h-4 text-purple-500 rotate-45" />
                        Top Categories
                    </h3>
                    <div className="flex items-center gap-2">
                        {!isBreakdownExpanded && analytics.categories.length > 0 && (
                             <span className="text-xs text-gray-500 dark:text-gray-400 font-medium">
                                {analytics.categories.length} found
                             </span>
                        )}
                        <button className={`p-1.5 rounded-full bg-gray-100 dark:bg-gray-800 text-gray-500 transition-transform duration-300 ${isBreakdownExpanded ? 'rotate-180' : ''}`}>
                            <ChevronDown className="w-4 h-4" />
                        </button>
                    </div>
                </div>

                {analytics.categories.length === 0 ? (
                    <p className="text-sm text-gray-500 text-center py-4">No expense data yet.</p>
                ) : (
                    <>
                        {/* Collapsed State: Segmented Progress Bar */}
                        {!isBreakdownExpanded && (
                            <div className="animate-fade-in-up">
                                <div className="h-4 w-full bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden flex">
                                    {analytics.categories.map((cat, i) => (
                                        <Tooltip 
                                            key={cat.name} 
                                            content={`${cat.name}: ${cat.percentage.toFixed(1)}%`}
                                        >
                                            <div 
                                                className={`h-full ${colors[i % colors.length]} transition-all duration-500`} 
                                                style={{ width: `${cat.percentage}%` }}
                                            />
                                        </Tooltip>
                                    ))}
                                </div>
                                <div className="flex justify-between mt-2">
                                     <div className="flex gap-3 overflow-hidden">
                                         {analytics.categories.slice(0, 3).map((cat, i) => (
                                             <div key={cat.name} className="flex items-center gap-1.5">
                                                 <div className={`w-2 h-2 rounded-full ${colors[i % colors.length]}`} />
                                                 <span className="text-xs text-gray-600 dark:text-gray-400 font-medium truncate max-w-[80px]">{cat.name}</span>
                                             </div>
                                         ))}
                                     </div>
                                     {analytics.categories.length > 3 && (
                                         <span className="text-xs text-gray-400 font-medium">+{analytics.categories.length - 3} more</span>
                                     )}
                                </div>
                            </div>
                        )}

                        {/* Expanded State: Detailed List */}
                        {isBreakdownExpanded && (
                            <div className="space-y-5 animate-fade-in-up mt-2">
                                {analytics.categories.map((cat, i) => (
                                    <div key={cat.name}>
                                        <div className="flex justify-between text-sm mb-2 font-medium">
                                            <span className="text-gray-700 dark:text-gray-300 flex items-center gap-2">
                                                <div className={`w-2 h-2 rounded-full ${colors[i % colors.length]}`}></div>
                                                {cat.name}
                                            </span>
                                            <span className="text-gray-900 dark:text-white">₹{cat.value.toLocaleString()}</span>
                                        </div>
                                        <div className="h-2 w-full bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
                                            <div 
                                                className={`h-full rounded-full ${colors[i % colors.length]}`} 
                                                style={{ width: `${cat.percentage}%`, transition: 'width 1s ease-out' }}
                                            ></div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
};

export default FinanceAnalytics;

import { Transaction, Note } from '../types';
import { getNotes, saveNote, getTransactions, getFinanceProfiles } from './dbService';
import { User } from '@supabase/supabase-js';

const LINK_TAG_PREFIX = 'wallet:';

/**
 * Helper to get the specific tag string for a wallet profile.
 */
const getWalletTag = (profileId: string | undefined | null) => {
    return `${LINK_TAG_PREFIX}${profileId || 'default'}`;
};

/**
 * Links a wallet (profile) to a specific note ID by adding a special tag to the note.
 * Removes the tag from any other notes to ensure a 1:1 mapping for this wallet.
 */
export const linkWalletToNote = async (user: User | null, profileId: string | null, note: Note) => {
    const targetTag = getWalletTag(profileId);
    const allNotes = await getNotes(user);

    // 1. Remove this wallet tag from ANY other notes to ensure uniqueness
    const oldLinkedNotes = allNotes.filter(n => n.tags?.includes(targetTag) && n.id !== note.id);

    for (const oldNote of oldLinkedNotes) {
        const newTags = (oldNote.tags || []).filter(t => t !== targetTag);
        await saveNote({ ...oldNote, tags: newTags, updatedAt: new Date().toISOString() }, user);
    }

    // 2. Add the tag to the target note if not present
    if (!note.tags?.includes(targetTag)) {
        const newTags = [...(note.tags || []), targetTag];
        await saveNote({ ...note, tags: newTags, updatedAt: new Date().toISOString() }, user);
    }
};

/**
 * Fetch the actual Note object linked to the current profile by looking for the tag.
 */
export const fetchLinkedNote = async (user: User | null, profileId: string | undefined | null): Promise<Note | undefined> => {
    const targetTag = getWalletTag(profileId);
    const allNotes = await getNotes(user);

    const candidates = allNotes.filter(n => n.tags?.includes(targetTag));
    return candidates.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())[0];
};

// --- NATURAL LANGUAGE GENERATION ---

const formatCurrency = (amount: number) => `₹${amount.toLocaleString('en-IN')}`;

const cleanText = (str: string) => {
    if (!str) return '';
    return str.replace(/[*_`\[\]~]/g, '').trim();
};

/**
 * Generates a structured, natural language line for the note.
 */
const generateLogLine = (t: Transaction): string => {
    const dateObj = new Date(t.transaction_date);
    const timeStr = dateObj.toLocaleTimeString('en-US', { 
        hour: '2-digit', 
        minute: '2-digit', 
        hour12: true 
    }).replace(/\s+/g, ' ').trim();

    // Dynamic Styles
    let amountClass = 'text-gray-900 dark:text-gray-100';
    let iconClass = 'fi-expense text-gray-500'; // Default

    // Category Code-Pill Styles
    let catBg = 'bg-gray-100 dark:bg-gray-800';
    let catText = 'text-gray-700 dark:text-gray-300';
    let catBorder = 'border-gray-200 dark:border-gray-700';

    if (t.type === 'income') {
        amountClass = 'text-emerald-600 dark:text-emerald-400';
        iconClass = 'fi-income text-emerald-500';

        catBg = 'bg-emerald-100 dark:bg-emerald-900/40';
        catText = 'text-emerald-800 dark:text-emerald-300';
        catBorder = 'border-emerald-200 dark:border-emerald-800/50';

    } else if (t.type === 'expense') {
        amountClass = 'text-rose-600 dark:text-rose-400';
        iconClass = 'fi-expense text-rose-500';

        catBg = 'bg-rose-100 dark:bg-rose-900/40';
        catText = 'text-rose-800 dark:text-rose-300';
        catBorder = 'border-rose-200 dark:border-rose-800/50';

    } else {
        amountClass = 'text-indigo-600 dark:text-indigo-400';
        iconClass = 'fi-transfer text-indigo-500';

        catBg = 'bg-indigo-100 dark:bg-indigo-900/40';
        catText = 'text-indigo-800 dark:text-indigo-300';
        catBorder = 'border-indigo-200 dark:border-indigo-800/50';
    }

    const iconHtml = `<span class="f-icon ${iconClass}"></span>`;

    // Styled Components for Markdown
    const amountHtml = `<span class="${amountClass} font-mono font-bold tracking-tight">${formatCurrency(t.amount)}</span>`;
    const timeHtml = `<span class="text-[10px] text-gray-400 dark:text-gray-500 font-mono ml-2 opacity-60">${timeStr}</span>`;

    // Updated Category HTML to mimic code block/pill style with specific colors
    const categoryHtml = `<span class="px-1.5 py-0.5 rounded-[4px] text-[11px] font-mono font-bold tracking-wide border ${catBorder} ${catBg} ${catText}">${cleanText(t.category)}</span>`;

    // Description in muted styling
    const descriptionClean = cleanText(t.description || '');
    let descHtml = '';

    if (descriptionClean && descriptionClean.toLowerCase() !== t.category.toLowerCase()) {
        descHtml = ` <span class="text-gray-500 dark:text-gray-400 text-xs">— ${descriptionClean}</span>`;
    }

    // High value alert
    const isHighValue = t.amount >= 5000;
    const alert = isHighValue ? '<span class="f-icon fi-alert text-amber-500"></span> ' : '';

    return `- ${alert}${iconHtml} ${categoryHtml} &nbsp;${amountHtml} ${descHtml} ${timeHtml} <!-- tx_id:${t.id} ts:${dateObj.getTime()} -->`;
};

// Return a CLEAN DATE STRING (e.g. "Monday, Oct 24") for grouping
const getDateString = (isoDate: string): string => {
    const dateObj = new Date(isoDate);
    const options: Intl.DateTimeFormatOptions = { weekday: 'long', month: 'short', day: 'numeric' };
    return dateObj.toLocaleDateString('en-US', options);
}

// Generates the visual HTML Header for a date
const generateDateHeaderHtml = (dateStr: string): string => {
    // Uses HTML h3 with specific margins to avoid extra whitespace
    // Reduced mt-5 to mt-4 to tighten spacing further
    return `<h3 class="flex items-center gap-2 text-sm font-bold text-gray-800 dark:text-gray-200 mt-4 mb-2"><span class="f-icon fi-calendar text-gray-500"></span> ${dateStr}</h3>`;
};

const parseLineStats = (line: string) => {
    const amountMatch = line.match(/₹([\d,]+)/);
    const amount = amountMatch ? parseInt(amountMatch[1].replace(/,/g, ''), 10) : 0;

    let type: 'income' | 'expense' | 'transfer' | 'unknown' = 'unknown';
    // Check for specific icon classes in the HTML string
    if (line.includes('fi-income')) type = 'income';
    else if (line.includes('fi-expense')) type = 'expense';
    else if (line.includes('fi-transfer')) type = 'transfer';
    // Fallback for backward compatibility with emojis
    else if (line.includes('💰')) type = 'income';
    else if (line.includes('💸')) type = 'expense';
    else if (line.includes('🔄')) type = 'transfer';

    return { type, amount };
};

const generateFooterStats = (txLines: string[]): string => {
    let income = 0;
    let expense = 0;

    txLines.forEach(line => {
        const { type, amount } = parseLineStats(line);
        if (type === 'income') income += amount;
        if (type === 'expense') expense += amount;
    });

    if (income === 0 && expense === 0) return '';

    const balance = income - expense;
    const sign = balance >= 0 ? '+' : '-';

    const incomePart = `<span class="f-icon fi-income text-emerald-500"></span> <span class="text-emerald-600 dark:text-emerald-400 font-mono font-bold text-xs">₹${income.toLocaleString('en-IN')}</span>`;
    const expensePart = `<span class="f-icon fi-expense text-rose-500"></span> <span class="text-rose-600 dark:text-rose-400 font-mono font-bold text-xs">₹${expense.toLocaleString('en-IN')}</span>`;
    const balancePart = `<span class="f-icon fi-wallet text-gray-800 dark:text-gray-200"></span> <span class="text-gray-900 dark:text-white font-mono font-extrabold text-xs">${sign}₹${Math.abs(balance).toLocaleString('en-IN')}</span>`;

    // Structured Blockquote Footer with Small, Normal Font. Wrapped in not-italic to override blockquote default.
    return `> <span class="not-italic"><span class="text-[10px] text-gray-400 dark:text-gray-500 font-bold uppercase tracking-wider">Daily Total</span> &nbsp; ${incomePart} &nbsp;<span class="text-gray-300 dark:text-gray-600 text-[10px]">|</span>&nbsp; ${expensePart} &nbsp;<span class="text-gray-300 dark:text-gray-600 text-[10px]">|</span>&nbsp; ${balancePart}</span> <!-- daily_stats -->`;
};

/**
 * Generates the "Final Verdict" card for the day.
 * MINIFIED to prevent extra lines in Markdown rendering.
 */
const generateDailyVerdict = (txs: Transaction[]): string => {
    let income = 0;
    let expense = 0;
    const catTotals: Record<string, number> = {};

    txs.forEach(t => {
        const amt = Number(t.amount);
        if (t.type === 'income') income += amt;
        if (t.type === 'expense') {
            expense += amt;
            catTotals[t.category] = (catTotals[t.category] || 0) + amt;
        }
    });

    if (income === 0 && expense === 0) return '';

    // Determine Top Category
    const topCategory = Object.entries(catTotals).sort((a, b) => b[1] - a[1])[0];
    const topCatName = topCategory ? topCategory[0] : 'None';
    const topCatAmount = topCategory ? topCategory[1] : 0;

    // Determine Sentiment
    let verdictTitle = "Balanced Day";
    let verdictColor = "text-blue-600 dark:text-blue-400";
    let verdictBg = "bg-blue-50 dark:bg-blue-900/10 border-blue-100 dark:border-blue-900/20";
    let iconClass = "fi-wallet";

    if (income > expense * 1.5) {
        verdictTitle = "Savings Day";
        verdictColor = "text-emerald-600 dark:text-emerald-400";
        verdictBg = "bg-emerald-50 dark:bg-emerald-900/10 border-emerald-100 dark:border-emerald-900/20";
        iconClass = "fi-income";
    } else if (expense > income && income > 0) {
        verdictTitle = "High Spend";
        verdictColor = "text-rose-600 dark:text-rose-400";
        verdictBg = "bg-rose-50 dark:bg-rose-900/10 border-rose-100 dark:border-rose-900/20";
        iconClass = "fi-expense";
    } else if (expense > 2000) {
        verdictTitle = "Heavy Expenses";
