// --- CONTENT MANIPULATION LOGIC ---

/**
 * Robustly rebuilds the note content.
 * 1. Preserves manual user text.
 * 2. Removes stale transaction lines and old stats.
 * 3. Re-inserts ALL current transactions in correct order.
 * 4. Places Daily Stats at the BOTTOM of each date block.
 * 5. Updates Snapshot Header table.
 */
const rebuildNoteContent = (existingContent: string, transactions: Transaction[], profileName: string): string => {
    const lines = existingContent.split('\n');

    // 1. Extract Manual Content (Anything not a tx_id line, not a Snapshot header, not an auto-generated Day header/footer)
    const manualLines: { text: string, dateContext?: string }[] = [];

    let currentDateContext: string | undefined = undefined;

    lines.forEach(line => {
        const trimmedLine = line.trim();
        // Skip Old Snapshot Header lines (Aggressive cleanup of old formats)
        if (line.startsWith('# 📊 Snapshot:') || line.startsWith('# 🪙') || line.startsWith('### ⚡') || line.startsWith('### 📊') || line.startsWith('### 💡')) return;
        if (line.startsWith('| <span') || line.startsWith('| :---') || line.startsWith('| **') || line.startsWith('| Category')) return;
        if (line.includes('Total Articles Updated') || line.includes('Last Update:') || line.includes('Last Synced:')) return;

        // Skip grid div lines from new stats cards and insights
        if (line.includes('<!-- FINANCE_WIDGET_START -->') || line.includes('<!-- FINANCE_WIDGET_END -->') || line.includes('<div class="grid') || line.includes('f-icon fi-income') || line.includes('f-icon fi-expense') || line.includes('Tx Volume') || line.includes('Daily Avg') || line.includes('Spending by Category')) return;

        // Skip Custom HTML headers for Breakdown and Insights and the new HR
        if (line.includes('Expense Breakdown</h3>') || line.includes('Key Insights</h3>') || line.includes('Report</h1>') || line.includes('<hr class="my-1')) return;

        // Skip Table Rows from previous snapshots (catch-all for table syntax if not caught above)
        // We only skip tables that look like generated stats (starting with pipe)
        if (trimmedLine.startsWith('|') && (trimmedLine.includes('Income') || trimmedLine.includes('Expense') || trimmedLine.includes('Trend') || trimmedLine.includes('Category'))) return;

        // Track Date Context - Supports both Markdown (###) and HTML (<h3) Header formats
        // We standardize the key to the plain text date string (e.g., "Monday, Oct 24")
        if (line.startsWith('###') || line.startsWith('<h3')) {
            if (line.includes('fi-calendar') || line.includes('🗓️')) {
                 // Remove tags to get the pure date string key
                 const baseMatch = line.replace(/###/g, '').replace(/<[^>]*>/g, '').replace('🗓️', '').trim();
                 currentDateContext = baseMatch; // Key: "Monday, Oct 24"
                 return;
            }
        }

        // Ignore auto-generated transaction lines
        if (line.includes('<!-- tx_id:')) return;

        // Ignore auto-generated daily stats footer (Supports various versions)
        if (line.includes('<!-- daily_stats -->') || trimmedLine.startsWith('**Daily Total:**') || trimmedLine.includes('Daily Total')) return;

        // Ignore auto-generated verdicts
        if (line.includes('<!-- daily_verdict_start -->') || line.includes('<!-- daily_verdict_end -->') || (line.includes('f-icon') && line.includes('Verdict'))) return;

        // Ignore separators at the top (likely from old header)
        if (trimmedLine === '---' && manualLines.length === 0) return;

        // Keep blank lines or actual user notes
        if (trimmedLine !== '') {
            manualLines.push({ text: line, dateContext: currentDateContext });
        }
    });

    // 2. Group Transactions by Date String Key
    const groupedTxs: Record<string, Transaction[]> = {};
    transactions.forEach(t => {
        const headerKey = getDateString(t.transaction_date);
        if (!groupedTxs[headerKey]) groupedTxs[headerKey] = [];
        groupedTxs[headerKey].push(t);
    });

    // 3. Build New Content
    // Removed trailing newlines to prevent gap
    let newContent = generateSnapshotHeader(transactions, profileName); 

    // Get all unique date keys (from both DB transactions and Manual notes that had a context)
    const allHeaders = new Set([...Object.keys(groupedTxs), ...manualLines.map(m => m.dateContext).filter(Boolean) as string[]]);

    // Sort keys ASCENDING (Oldest date first)
    const sortedHeaders = Array.from(allHeaders).sort((a, b) => {
        const dateA = new Date(a + ` ${new Date().getFullYear()}`); 
        const dateB = new Date(b + ` ${new Date().getFullYear()}`);
        return dateA.getTime() - dateB.getTime(); 
    });

    sortedHeaders.forEach((headerKey, index) => {
        const txs = groupedTxs[headerKey] || [];
        const manualNotesForDay = manualLines.filter(m => m.dateContext === headerKey);

        // Add HTML Header for this day
        newContent += `\n${generateDateHeaderHtml(headerKey)}\n`;

        // Add Transactions (Sorted by time ascending)
        const txLines = txs
            .sort((a, b) => new Date(a.transaction_date).getTime() - new Date(b.transaction_date).getTime())
            .map(generateLogLine);

        if (txLines.length > 0) {
            newContent += txLines.join('\n') + '\n';
        }

        // Add Manual Notes for this day
        if (manualNotesForDay.length > 0) {
            newContent += '\n' + manualNotesForDay.map(m => m.text).join('\n') + '\n';
        }

        // Add Footer Stats
        if (txLines.length > 0) {
             const footer = generateFooterStats(txLines);
             if (footer) newContent += footer + '\n';

             // NEW: Add Verdict after footer
             const verdict = generateDailyVerdict(txs);
             if (verdict) newContent += verdict + '\n';
        }

        // Add Separator if not last
        if (index < sortedHeaders.length - 1) {
            newContent += '---\n';
        }
    });

    // Append Orphaned Manual Notes (notes that lost their date header context)
    const orphanedNotes = manualLines.filter(m => !m.dateContext);
    if (orphanedNotes.length > 0) {
        newContent += '\n\n### 📝 Notes\n' + orphanedNotes.map(m => m.text).join('\n');
    }

    return newContent.trim();
};

/**
 * Helper to get wallet name quickly if not provided
 */
const getProfileName = async (user: User | null, profileId: string | null | undefined): Promise<string> => {
    if (!profileId) return 'Main Wallet';
    const profiles = await getFinanceProfiles(user);
    const p = profiles.find(pr => pr.id === profileId);
    return p ? p.name : 'Wallet';
}

// --- PUBLIC API ---

export const syncAllTransactionsToNote = async (user: User | null, profileId: string | null, profileName: string): Promise<boolean> => {
    try {
        const note = await fetchLinkedNote(user, profileId);
        if (!note) return false;

        // Fetch ALL transactions for this profile
        const allTransactions = await getTransactions(user, profileId);

        // Rebuild entire note content
        const newContent = rebuildNoteContent(note.content || '', allTransactions, profileName);

        await saveNote({ ...note, content: newContent, updatedAt: new Date().toISOString() }, user);
        return true;
    } catch (e) {
        console.error("Sync All Failed", e);
        return false;
    }
};

export const syncTransactionAdd = async (user: User | null, transaction: Transaction): Promise<boolean> => {
    const profileName = await getProfileName(user, transaction.profile_id);
    return syncAllTransactionsToNote(user, transaction.profile_id || null, profileName);
};

export const syncTransactionDelete = async (user: User | null, transactionId: string, profileId: string | undefined | null): Promise<boolean> => {
    const profileName = await getProfileName(user, profileId);
    return syncAllTransactionsToNote(user, profileId || null, profileName);
};

export const syncTransactionUpdate = async (user: User | null, transaction: Transaction): Promise<boolean> => {
    const profileName = await getProfileName(user, transaction.profile_id);
    return syncAllTransactionsToNote(user, transaction.profile_id || null, profileName);
};

